 1	import * as React from 'react';
 2	import {
 3	  ExternalCephStateValues,
 4	  ExternalCephStateKeys,
 5	} from '@odf/core/types';
 6	import { StorageClassWizardStepExtensionProps as ExternalStorage } from '@odf/odf-plugin-sdk/extensions';
 7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 8	import { Text, TextContent, TextVariants } from '@patternfly/react-core';
 9	import { getExternalStorage } from '../../utils';
10	import { WizardDispatch, WizardState } from '../reducer';
11	
12	export const ConnectionDetails: React.FC<ConnectionDetailsProps> = ({
13	  state,
14	  externalStorage,
15	  dispatch,
16	  supportedExternalStorage,
17	}) => {
18	  const { component: Component } =
19	    getExternalStorage(externalStorage, supportedExternalStorage) || {};
20	
21	  const { t } = useCustomTranslation();
22	
23	  const setForm = React.useCallback(
24	    (field: ExternalCephStateKeys, value: ExternalCephStateValues) =>
25	      dispatch({
26	        type: 'wizard/setConnectionDetails',
27	        payload: {
28	          field,
29	          value,
30	        },
31	      }),
32	    [dispatch]
33	  );
34	
35	  return (
36	    <>
37	      <TextContent>
38	        <Text component={TextVariants.h3}>{t('Connection details')}</Text>
39	      </TextContent>
40	      {Component && <Component setFormState={setForm} formState={state} />}
41	    </>
42	  );
43	};
44	
45	type ConnectionDetailsProps = {
46	  state: WizardState['createStorageClass'];
47	  externalStorage: WizardState['backingStorage']['externalStorage'];
48	  dispatch: WizardDispatch;
49	  supportedExternalStorage: ExternalStorage[];
50	};

